// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";


// Interface for GreenToken to mint rewards after approval
interface IGreenToken {
    function mint(address to, uint256 amount) external;

    // Used for performing GT deduction (minority penalty / non-voting penalty)
    function slash(address user, uint256 amount) external returns (uint256 actualAmount);
}

// RewardToken interface, used for majority rewards +1 RT
interface IRewardToken {
    function mint(address to, uint256 amount) external;
}

// Interface for CommitteeManager to verify voter identity and thresholds
interface ICommitteeManager {
    function isCommitteeMember(address user) external view returns (bool);
    function approvalThreshold() external view returns (uint256);
    function getMemberCount() external view returns (uint256);

    // get the member list for validator assignment
    function getMembers() external view returns (address[] memory);
}

contract ActivityVerification is ReentrancyGuard {
    // Custom errors for clear failure reasons
    error NotCommitteeMember();
    error AlreadyVoted();
    error TaskNotPending();
    error TaskNotFound();
    error CannotVoteOnOwnSubmission(); // Prevent self-voting

    // Verifier / Quota / Queuing-related errors
    error NotAssignedVerifier();
    error SubmissionLimitReached();
    error InvalidReward();
    error NothingQueued();
    error QueueNotReady();

    // Task lifecycle status
    enum TaskStatus { Pending, Approved, Rejected }

    // Structure to store activity task details
    struct Task {
        address submitter;   // Student address
        string actionType;   // e.g., "Recycling", "Tree Planting"
        string proofCID;     // IPFS hash for proof image/document
        uint256 gtReward;    // Requested GreenToken amount
        uint256 approvals;   // Vote counter
        uint256 rejections;  // Vote counter
        TaskStatus status;   // Current status
        uint256 timestamp;   // Submission time

        // Voting deadline (12 hours)
        uint256 voteDeadline;

        // If the daily GT limit is exceeded, rewards will be placed in a queue for later redemption
        bool gtQueued;
        bool gtClaimed;

        // Assign 3 verifiers to each task
        address[3] verifiers;
        uint8 verifierCount;
    }

    // External contract instances
    IGreenToken public immutable greenToken;

    // Used to distribute majority rewards RT
    IRewardToken public immutable rewardToken;

    ICommitteeManager public immutable committeeManager;
    
    // State variables
    uint256 public taskCount;
    mapping(uint256 => Task) public tasks;
    mapping(uint256 => mapping(address => bool)) public hasVoted; // Tracking voters per task

    // Record the direction of the vote to determine the majority or minority
    mapping(uint256 => mapping(address => bool)) public voteChoice;

    // System parameters for verification, incentives, penalties, and constraints
    uint256 public constant verifierReward = 1;      // +1 RT
    uint256 public constant verifierPenalty = 5;     // -5 GT
    uint256 public constant inactivityPenalty = 2;   // -2 GT
    uint256 public constant dailyMintCap = 300;      // 300 GT/day
    uint256 public constant avgGTperTask = 5;        // 5 GT/task
    uint256 public constant maxTasksPerDay = 60;     // 60 tasks/day
    uint256 public constant userTaskLimit = 2;       // 2 submissions/day/user
    uint256 public constant verifierTaskLimit = 8;   // 8 reviews/day/verifier
    uint256 public constant voteDeadlineDuration = 12 hours;

    // Daily statistics
    mapping(uint256 => uint256) public dailyMintedGT;
    mapping(uint256 => uint256) public dailyTaskCount;
    mapping(address => mapping(uint256 => uint256)) public userDailySubmissions;
    mapping(address => mapping(uint256 => uint256)) public verifierDailyAssigned;

    // Events for frontend and indexing
    event TaskSubmitted(uint256 indexed taskId, address indexed submitter, string actionType, uint256 gtReward);
    event VoteCast(uint256 indexed taskId, address indexed voter, bool approve);
    event TaskFinalized(uint256 indexed taskId, TaskStatus status);

    // Verifier assigns and queues reward redemption events
    event VerifiersAssigned(uint256 indexed taskId, address[3] verifiers);
    event QueuedGTClaimed(uint256 indexed taskId, address indexed submitter, uint256 amount);

    // Modifier to restrict access to committee members only
    modifier onlyCommittee() {
        if (!committeeManager.isCommitteeMember(msg.sender)) revert NotCommitteeMember();
        _;
    }

    // Initialize with related contract addresses
    constructor(address _greenToken, address _rewardToken, address _committeeManager) {
        greenToken = IGreenToken(_greenToken);
        rewardToken = IRewardToken(_rewardToken);
        committeeManager = ICommitteeManager(_committeeManager);
    }

    // Calculate the current day and use it for the daily limit.
    function currentDay() public view returns (uint256) {
        return block.timestamp / 1 days;
    }

    // Students call this to submit their green activity for verification
    function submitTask(
        string calldata _actionType,
        string calldata _proofCID,
        uint256 _gtReward
    ) external returns (uint256 taskId) {
        uint256 dayKey = currentDay();

        // Set the reward for regular tasks to 5 GT
        if (_gtReward != avgGTperTask) revert InvalidReward();

        // Each user may submit up to 2 tasks per day.
        if (userDailySubmissions[msg.sender][dayKey] >= userTaskLimit) {
            revert SubmissionLimitReached();
        }

        // A maximum of 60 tasks per day across the entire system
        require(dailyTaskCount[dayKey] < maxTasksPerDay, "Daily task cap reached");

        taskId = taskCount++;
        Task storage t = tasks[taskId];
        t.submitter = msg.sender;
        t.actionType = _actionType;
        t.proofCID = _proofCID;
        t.gtReward = _gtReward;
        t.status = TaskStatus.Pending;
        t.timestamp = block.timestamp;

        // Set a 12-hour voting deadline
        t.voteDeadline = block.timestamp + voteDeadlineDuration;

        userDailySubmissions[msg.sender][dayKey]++;
        dailyTaskCount[dayKey]++;

        // Automatically assign 3 verifiers
        _assignVerifiers(taskId);

        emit TaskSubmitted(taskId, msg.sender, _actionType, _gtReward);
        emit VerifiersAssigned(taskId, t.verifiers);
    }

    // Committee members call this to approve or reject a task
    function voteOnTask(uint256 _taskId, bool _approve) external onlyCommittee nonReentrant {
        // Ensure the task exists
        if (_taskId >= taskCount) revert TaskNotFound();
        
        Task storage t = tasks[_taskId];
        
        // Implementation: Submitter cannot be the voter for their own task
        if (msg.sender == t.submitter) revert CannotVoteOnOwnSubmission();

        // Check task status and voting history
        if (t.status != TaskStatus.Pending) revert TaskNotPending();
        if (hasVoted[_taskId][msg.sender]) revert AlreadyVoted();

        // Only assigned verifiers may vote
        if (!_isAssignedVerifier(t, msg.sender)) revert NotAssignedVerifier();

        // Record the vote
        hasVoted[_taskId][msg.sender] = true;

        // Record the direction of votes for use in future majority rewards/minority penalties
        voteChoice[_taskId][msg.sender] = _approve;

        if (_approve) {
            t.approvals++;
        } else {
            t.rejections++;
        }

        emit VoteCast(_taskId, msg.sender, _approve);

        // Get approval threshold from CommitteeManager
        uint256 threshold = committeeManager.approvalThreshold();
        
        // Once the threshold is reached or all three verifiers have cast their votes,
        // the system proceeds to a unified settlement
        if (
            t.approvals >= threshold ||
            t.rejections > (committeeManager.getMemberCount() - threshold) ||
            _allVerifiersVoted(t, _taskId)
        ) {
            _finalizeTask(_taskId, threshold);
        }
    }

    // After the voting period expires, anyone can trigger the settlement process
    function finalizeExpiredTask(uint256 _taskId) external nonReentrant {
        if (_taskId >= taskCount) revert TaskNotFound();

        Task storage t = tasks[_taskId];
        if (t.status != TaskStatus.Pending) revert TaskNotPending();
        require(block.timestamp > t.voteDeadline, "Deadline not reached");

        uint256 threshold = committeeManager.approvalThreshold();
        _finalizeTask(_taskId, threshold);
    }

    // If the daily GT quota is full, you can still claim the waiting-list reward later
    function claimQueuedGT(uint256 _taskId) external nonReentrant {
        if (_taskId >= taskCount) revert TaskNotFound();

        Task storage t = tasks[_taskId];
        uint256 dayKey = currentDay();

        require(msg.sender == t.submitter, "Not submitter");
        if (!t.gtQueued || t.gtClaimed) revert NothingQueued();
        if (dailyMintedGT[dayKey] + t.gtReward > dailyMintCap) revert QueueNotReady();

        dailyMintedGT[dayKey] += t.gtReward;
        t.gtClaimed = true;

        greenToken.mint(t.submitter, t.gtReward);

        emit QueuedGTClaimed(_taskId, msg.sender, t.gtReward);
    }

    // Get the verifier assigned to a specific task
    function getTaskVerifiers(uint256 _taskId) external view returns (address[3] memory) {
        if (_taskId >= taskCount) revert TaskNotFound();
        return tasks[_taskId].verifiers;
    }

    // Internal settlement function
    function _finalizeTask(uint256 _taskId, uint256 threshold) internal {
        Task storage t = tasks[_taskId];

        if (t.approvals >= threshold) {
            // Task Approved: Update status and mint GreenTokens to student
            t.status = TaskStatus.Approved;

            // First, check if the dailyMintCap has been exceeded
            _mintOrQueueGT(t);

            // Settle rewards and penalties after verification
            _settleVerifierRewardsAndPenalties(_taskId, true);

            emit TaskFinalized(_taskId, TaskStatus.Approved);
        } else {
            // Task Rejected: Too many rejections, cannot reach threshold
            t.status = TaskStatus.Rejected;

            // Settle verifier rewards and penalties even after rejection
            _settleVerifierRewardsAndPenalties(_taskId, false);

            emit TaskFinalized(_taskId, TaskStatus.Rejected);
        }
    }

    // If the daily GT quota has not been exceeded, mint immediately; otherwise, join the queue
    function _mintOrQueueGT(Task storage t) internal {
        uint256 dayKey = currentDay();

        if (dailyMintedGT[dayKey] + t.gtReward <= dailyMintCap) {
            dailyMintedGT[dayKey] += t.gtReward;
            t.gtClaimed = true;
            greenToken.mint(t.submitter, t.gtReward);
        } else {
            t.gtQueued = true;
            t.gtClaimed = false;
        }
    }

    // Verifier Rewards And Penalties
    // Majority: +1 RT
    // Minority: -5 GT
    // Abstained: -2 GT
    function _settleVerifierRewardsAndPenalties(uint256 _taskId, bool approved) internal {
        Task storage t = tasks[_taskId];

        for (uint256 i = 0; i < t.verifierCount; i++) {
            address verifier = t.verifiers[i];
            bool voted = hasVoted[_taskId][verifier];

            if (!voted) {
                greenToken.slash(verifier, inactivityPenalty);
                continue;
            }

            bool votedApprove = voteChoice[_taskId][verifier];
            bool inMajority = (approved && votedApprove) || (!approved && !votedApprove);

            if (inMajority) {
                rewardToken.mint(verifier, verifierReward);
            } else {
                greenToken.slash(verifier, verifierPenalty);
            }
        }
    }

    // Assign 3 verifiers and limit each verifier to a maximum of 8 tasks per day
    function _assignVerifiers(uint256 _taskId) internal {
        Task storage t = tasks[_taskId];
        address[] memory members = committeeManager.getMembers();
        uint256 dayKey = currentDay();
        uint8 selected = 0;

        for (uint256 i = 0; i < members.length && selected < 3; i++) {
            address candidate = members[i];

            if (candidate == t.submitter) continue;
            if (verifierDailyAssigned[candidate][dayKey] >= verifierTaskLimit) continue;

            t.verifiers[selected] = candidate;
            verifierDailyAssigned[candidate][dayKey]++;
            selected++;
        }

        require(selected == 3, "Need 3 eligible verifiers");
        t.verifierCount = selected;
    }

    // Determine whether a given address is the verifier for this task
    function _isAssignedVerifier(Task storage t, address user) internal view returns (bool) {
        for (uint256 i = 0; i < t.verifierCount; i++) {
            if (t.verifiers[i] == user) return true;
        }
        return false;
    }

    // Determine whether all verifiers have voted
    function _allVerifiersVoted(Task storage t, uint256 _taskId) internal view returns (bool) {
        for (uint256 i = 0; i < t.verifierCount; i++) {
            if (!hasVoted[_taskId][t.verifiers[i]]) return false;
        }
        return true;
    }
}

Contracts/AMMPool.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

// author Su Yan

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

// use this interface to check if an address is a committee member
interface ICommitteeManager {
    function isCommitteeMember(address account) external view returns (bool);
}


contract AMMPool is ReentrancyGuard {
    // custom errors
    // GT address is zero
    error InvalidGTAddress();

    // RT address is zero
    error InvalidRTAddress();

    // GT and RT cannot be the same token
    error SameTokenAddress();

    // pool was already initialized before
    error PoolAlreadyInitialized();

    // pool is not initialized yet
    error PoolNotInitialized();

    // GT amount cannot be 0
    error ZeroGTAmount();

    // RT amount cannot be 0
    error ZeroRTAmount();

    // GT transfer did not work
    error GTTransferFailed();

    // RT transfer did not work
    error RTTransferFailed();

    // input amount cannot be 0
    error ZeroAmountIn();

    // pool reserve is empty
    error EmptyReserve();

    // output amount is 0
    error ZeroAmountOut();

    // minimum output is not met
    error SlippageTooHigh();

    // GT input transfer failed
    error SwapGTTransferFailed();

    // RT output transfer failed
    error SwapRTTransferFailed();

    // RT input transfer failed
    error SwapRTInTransferFailed();

    // GT output transfer failed
    error SwapGTOutTransferFailed();

    // committee address is zero
    error InvalidCommitteeAddress();

    // caller is not a committee member
    error NotCommitteeMember();

    // fee recipient address is zero
    error InvalidFeeRecipient();

    // can't allow to save 0 in buffer
    error ZeroBufferAmount();

    // RT transfer to buffer failed
    error BufferRTTransferFailed();

    // buffer can't the max size
    error BufferSizeIsMax();

    // requested GT is bigger than the current immediate limit
    error EffectiveGTExceeded(uint256 requestedGT, uint256 allowedGT);


    // 10000 bp = 100%
    uint256 public constant BASIS_POINTS = 10000;

    // Version C update
    uint256 public constant MAX_SWAP_PER_USER = 50 * 1e18; // one user can only swap 50 gt one day
    uint256 public constant MAX_SWAP_PROPORTION = 4000; // 40% of user holdings in basis points
    uint256 public constant TARGET_RT = 3000 * 1e18; // target RT reserve
    uint256 public constant INJECT_TRIGGER = 4000; // trigger inject when reserveRT is below 40% of target
    uint256 public constant BUFFER_SIZE = 3600 * 1e18; // buffer can hold at most 3600 RT
    uint256 public constant BUFFER_ALERT = 900 * 1e18; // alert
    uint256 public constant COOLDOWN_INJECT = 1 days; // wait 24 hours between inject actions

    // Version C buffer state
    uint256 public bufferRT; // RT stored in buffer, not in swap reserve
    uint256 public lastInjectTime; // timestamp of the last inject action


    // save one user's daily GT swap usage
    struct DailyGTSwap { 
        uint256 day; // current day
        uint256 usedGT; // how much GT the user has used today
    }

    // save daily GT usage for each user
    mapping(address => DailyGTSwap) public dailyGTSwap;


    // define GT and RT
    IERC20 public greenToken;
    IERC20 public rewardToken;

    // define CommitteeManager
    ICommitteeManager public committeeManager;

    uint256 public reserveGT; // to see how much GT in this pool
    uint256 public reserveRT; // to see how much RT in this pool
    uint256 public k; // to define k(k = GT * RT)
    address public feeRecipient; // save the fee in this pool

    bool public initialized; // to check this pool if has been initialized





    // Event
    // send a event to show initial situation
    event PoolInitialized(uint256 gtAmount, uint256 rtAmount, uint256 newK);

    // log swap result
    event Swap(address indexed user, bool isGTtoRT, uint256 amountIn, uint256 amountOut, uint256 feeRate);

    // record who change the feerecipient
    event FeeRecipientUpdated(address indexed oldRecipient, address indexed newRecipient);

    // record buffer
    event BufferSituation(address indexed operator, uint256 amount, uint256 newBufferRT);

    // record auto inject result
    event RTInjected(address indexed operator, uint256 amount, uint256 newReserveRT, uint256 newBufferRT, uint256 newK);

    // record low buffer alert
    event BufferAlert(uint256 currentBufferRT);






    // add modifier onlyCommittee() to prevent unCommitteemember's action
    modifier onlyCommittee() {
        if (!committeeManager.isCommitteeMember(msg.sender)) revert NotCommitteeMember();
        else  _;
    }

    // save token address and target RT
    constructor(address gt, address rt, address committee) {
        // check GT address
        if (gt == address(0)) revert InvalidGTAddress();

        // check RT address
        if (rt == address(0)) revert InvalidRTAddress();

        // check CommitteeAddress
        if (committee == address(0)) revert InvalidCommitteeAddress();

        // GT and RT must be different
        if (gt == rt) revert SameTokenAddress();


        // input GT address
        greenToken = IERC20(gt);

        // input RT address
        rewardToken = IERC20(rt);


        // keep fee in this pool
        feeRecipient = address(this);

        // set committeeManager
        committeeManager = ICommitteeManager(committee);

        }


    // first time to add GT and RT into the pool
    function initialize(uint256 gtAmount, uint256 rtAmount) external onlyCommittee {
        // only allow once in the beginning
        if (initialized) revert PoolAlreadyInitialized();

        // the initial amount must more than 0
        if (gtAmount == 0) revert ZeroGTAmount();
        if (rtAmount == 0) revert ZeroRTAmount();

        // move GT from user to this pool(must approved)
        if (!greenToken.transferFrom(msg.sender, address(this), gtAmount)) {revert GTTransferFailed();}

        // move RT from user to this pool(must approved)
        if (!rewardToken.transferFrom(msg.sender, address(this), rtAmount)) {revert RTTransferFailed();}

        // save reserve
        reserveGT = gtAmount;
        reserveRT = rtAmount;

        // set initial k
        k = reserveGT * reserveRT;

        // set pool already initialized
        initialized = true;

        // log this situation
        emit PoolInitialized(gtAmount, rtAmount, k);

    }



    // check current pool reserves(GT and RT amounts) and k
    function getReserves() external view returns (uint256 gt, uint256 rt, uint256 currentK) {
        return (reserveGT, reserveRT, k);
    }

    // check current fee rate(10=10bp=0.1%) by RT reserve ratio 
    function getCurrentFeeRate() public view returns (uint256 bp) {
        // pool must be ready first
        if (!initialized) revert PoolNotInitialized();

        // more than 80% -> 10bp
        if (reserveRT * 100 > TARGET_RT * 80) {
            return 10;
        }

        // 60% to 80% -> 30bp
        if (reserveRT * 100 >= TARGET_RT * 60) {
            return 30;
        }

        // 40% to 60% -> 70bp
        if (reserveRT * 100 >= TARGET_RT * 40) {
            return 70;
        }

        // below 40% -> 150bp
        return 150;
    }



    // check output amount before swap
    function getAmountOut(uint256 amountIn, bool isGTtoRT) public view returns (uint256 amountOut){
        // pool must be ready first
        if (!initialized) revert PoolNotInitialized();

        // input amount must be greater than 0
        if (amountIn == 0) revert ZeroAmountIn();

        uint256 reserveIn;
        uint256 reserveOut;

        // choose input and output reserves by swap direction
        if (isGTtoRT) {
            reserveIn = reserveGT;
            reserveOut = reserveRT;
        } else {
            reserveIn = reserveRT;
            reserveOut = reserveGT;
        }

        // both sides must have reserve
        if (reserveIn == 0 || reserveOut == 0) revert EmptyReserve();

        // get current fee rate
        uint256 feeRate = getCurrentFeeRate();

        // apply fee on input amount first
        uint256 amountInWithFee = amountIn * (BASIS_POINTS - feeRate);

        // use the AMM formula to calculate output
        // input is charged with fee first
        // keep division at the end for better precision
        amountOut = (amountInWithFee * reserveOut) / (reserveIn * BASIS_POINTS + amountInWithFee);

        // do not allow zero output
        if (amountOut == 0) revert ZeroAmountOut();
    }




    // try to automatelly inject RT from buffer into reserve when needed
    function _autoInjectIfNeeded() internal {
        // calculate the RT trigger
        uint256 injectTriggerRT = (TARGET_RT * INJECT_TRIGGER) / BASIS_POINTS;

        // stop when reserve isn't low
        if (reserveRT >= injectTriggerRT) { return; }

        // stop when cooldown isn't end
        if (lastInjectTime != 0) { 
            // calculate the next inject time
            uint256 nextInjectTime = lastInjectTime + COOLDOWN_INJECT;
            // stop
            if (block.timestamp < nextInjectTime) { return; }
        }

        // send alert when buffer is empty
        if (bufferRT == 0) { emit BufferAlert(bufferRT); return; }

        // calculate how much RT to full the RT pool
        uint256 neededRT = TARGET_RT - reserveRT;

        uint256 injectAmount;
        // choose the smaller value between needed RT and buffer RT
        if (bufferRT < neededRT) {
            // buffer is smaller, so use all bufferRT
            injectAmount = bufferRT;
        } else { 
            // neededRT is smaller, so only use neededRT
            injectAmount = neededRT;
        }

        // move RT out from buffer
        bufferRT -= injectAmount;

        // add RT into reserve rt pool
        reserveRT += injectAmount;

        // save this time
        lastInjectTime = block.timestamp;

        // update k
        k = reserveGT * reserveRT;

        // record the inject result
        emit RTInjected(msg.sender, injectAmount, reserveRT, bufferRT, k);

        // send alert when buffer is low
        if (bufferRT < BUFFER_ALERT) { emit BufferAlert(bufferRT); }

    }



    // get current day
    function _getCurrentDay() internal view returns (uint256 day) {
        // use blockchain time and divide by one day
        return block.timestamp / 1 days;
    }


    // check how much GT one user used today
    function getUsedGTToday(address user) public view returns (uint256) {
        // get current day
        uint256 currentDay = _getCurrentDay();

        // return 0 when the saved record is from an old day
        if (dailyGTSwap[user].day != currentDay) { return 0; }

        // return today's used GT amount
        return dailyGTSwap[user].usedGT;
    }


    // check how much GT one user can still use today
    function getRemainingDailyGT(address user) public view returns (uint256) { 
        // get today's used GT amount
        uint256 usedToday = getUsedGTToday(user);

        // return 0 when the user already used all 
        if (usedToday >= MAX_SWAP_PER_USER) { return 0; }

        // return the remaining
        return MAX_SWAP_PER_USER - usedToday;
    }



    // add GT usage into today's record
    function _addDailyUsedGT(address user, uint256 amount) internal {
        // get current day
        uint256 currentDay = _getCurrentDay();

        // reset the record when a new day
         if (dailyGTSwap[user].day != currentDay) {
            dailyGTSwap[user].day = currentDay; dailyGTSwap[user].usedGT = 0;
         }

        // add today's used GT amount
        dailyGTSwap[user].usedGT += amount;

    }


    // check the 40% GT holding limit for one user
    function getHoldingLimitGT(address user) public view returns (uint256) {
        // get user's current GT
        uint256 userGT = greenToken.balanceOf(user);

        // return 40% of the user's GT
        return (userGT * MAX_SWAP_PROPORTION) / BASIS_POINTS;
    }



    // check the current immediate GT limit for one user (directly use it in front page)
     function getCurrentImmediateLimit(address user) public view returns (uint256) { 
        // get the user's remaining daily GT
        uint256 remainingDailyGT = getRemainingDailyGT(user);

        // get the user's 40% holding limit
        uint256 holdingLimitGT = getHoldingLimitGT(user);

        // return the smaller 
        if (remainingDailyGT < holdingLimitGT) { return remainingDailyGT; }

        else return holdingLimitGT;
     }



    // calculate how much GT can be swapped
    function _getEffectiveGT(address user, uint256 gtIn) internal view returns (uint256) {
        // get the user's current immediate limit
        uint256 immediateLimit = getCurrentImmediateLimit(user);


        // start with the input amount
        uint256 effectiveGT = gtIn;

        // use the smaller value 
        if (immediateLimit < effectiveGT)  { effectiveGT = immediateLimit; }


        // return the final
        return effectiveGT;
    }




    // swap GT for RT
    function swapGTforRT(uint256 gtIn, uint256 minRTOut) external nonReentrant returns (uint256 rtOut) {
        // pool must be ready first
        if (!initialized) revert PoolNotInitialized();

        // input must be greater than 0
        if (gtIn == 0) revert ZeroAmountIn();

        // automatically add RT reserve from buffer when needed
        _autoInjectIfNeeded();

        // calculate the current immediate GT limit for this user
        uint256 effectiveGT = _getEffectiveGT(msg.sender, gtIn);

        // stop when requested GT is above the immediate limit
        if (gtIn > effectiveGT) { revert EffectiveGTExceeded(gtIn, effectiveGT); }

        // get output before swap
        rtOut = getAmountOut(gtIn, true);

        // make sure output is not below user limit
        if (rtOut < minRTOut) revert SlippageTooHigh();

        // save fee rate for event log
        uint256 feeRate = getCurrentFeeRate();

        // move GT from user to pool
        if (!greenToken.transferFrom(msg.sender, address(this), gtIn)) { revert SwapGTTransferFailed();}

        // move RT from pool to user
        if (!rewardToken.transfer(msg.sender, rtOut)) { revert SwapRTTransferFailed();}

        // update pool reserves
        reserveGT += gtIn;
        reserveRT -= rtOut;

        // update k after swap
        k = reserveGT * reserveRT;

        // record today's used GT
        _addDailyUsedGT(msg.sender, gtIn);

        // automatically add RT reserve from buffer when needed
        _autoInjectIfNeeded();

        // show the current situation 
        emit Swap(msg.sender, true, gtIn, rtOut, feeRate);
    }



    // swap RT for GT
    function swapRTforGT(uint256 rtIn, uint256 minGTOut) external nonReentrant returns (uint256 gtOut){
        // pool must be ready first
        if (!initialized) revert PoolNotInitialized();

        // input must be greater than 0
        if (rtIn == 0) revert ZeroAmountIn();

        // get output before swap
        gtOut = getAmountOut(rtIn, false);

        // make sure output is not below user limit
        if (gtOut < minGTOut) revert SlippageTooHigh();

        // save fee rate for event log
        uint256 feeRate = getCurrentFeeRate();

        // move RT from user to pool
        if (!rewardToken.transferFrom(msg.sender, address(this), rtIn)) { revert SwapRTInTransferFailed();}

        // move GT from pool to user
        if (!greenToken.transfer(msg.sender, gtOut)) { revert SwapGTOutTransferFailed(); }

        // update pool reserves
        reserveRT += rtIn;
        reserveGT -= gtOut;

        // update k after swap
        k = reserveGT * reserveRT;

        // show the current situation
        emit Swap(msg.sender, false, rtIn, gtOut, feeRate);
    }



    // let committeeManager can change feerecipient address
    function setFeeRecipient(address newRecipient) external onlyCommittee {
        // do not allow the zero address
        if (newRecipient == address(0)) revert InvalidFeeRecipient();

        // save the old fee recipient for the event
        address oldRecipient = feeRecipient;

        // update the fee recipient
        feeRecipient = newRecipient;

        // record the change
        emit FeeRecipientUpdated(oldRecipient, newRecipient);
    }




    // committeeManager can inject RT into the buffer
    function BufferRTAction(uint256 amount) external onlyCommittee {
       // pool must be ready first 
       if (!initialized) revert PoolNotInitialized();

       // can't allow to save 0 in buffer
       if (amount == 0) revert ZeroBufferAmount();

       // buffer can't the max size
       if (bufferRT + amount > BUFFER_SIZE) revert BufferSizeIsMax();

       // RT transfer to buffer failed 
       if (!rewardToken.transferFrom(msg.sender, address(this), amount)) { revert BufferRTTransferFailed(); }

       // update RT reserve
       bufferRT += amount;

       // show the current situation
       emit BufferSituation(msg.sender, amount, bufferRT);
    }

    // see status to test and set front page
    function getPoolStatus() external view returns (uint256 currentReserveGT, uint256 currentReserveRT, uint256 currentBufferRT, uint256 currentK, uint256 currentLastInjectTime){
        return (reserveGT, reserveRT, bufferRT, k, lastInjectTime);
    }




}

